import { createDOMElem } from "domelemjs";
export function createParagraph(params) {
    const attrs = {};
    if (params.id)
        attrs.id = params.id;
    if (params.class)
        attrs.class = params.class;
    return createDOMElem({
        tag: "p",
        text: params.text,
        parent: params.parent,
        attrs,
    });
}
