import { createDOMElem } from "domelemjs";
export function createBadge(config) {
    const rootAttrs = { class: `badge badge-${config.type || "neutral"}${config.class ? ` ${config.class}` : ""}` };
    if (config.id)
        rootAttrs.id = config.id;
    return createDOMElem({ tag: "span", parent: config.parent, attrs: rootAttrs, text: config.text });
}
