import { createDOMElem } from "domelemjs";
import { highlightCode } from "./highlighter";
export function createCodeBlock(config) {
    const children = [];
    if (config.language) {
        children.push({
            tag: "div",
            text: config.language.toUpperCase(),
            attrs: { class: "code-language" },
        });
    }
    const highlighted = highlightCode(config.code, config.language);
    children.push({
        tag: "pre",
        attrs: { class: "code-pre" },
        children: [
            {
                tag: "code",
                content: highlighted,
                attrs: { class: `code-content${config.language ? ` language-${config.language}` : ""}` },
            },
        ],
    });
    const rootAttrs = {
        class: `code-block${config.class ? ` ${config.class}` : ""}`,
    };
    if (config.id)
        rootAttrs.id = config.id;
    const opts = {
        tag: "div",
        attrs: rootAttrs,
        children,
    };
    if (config.parent)
        opts.parent = config.parent;
    return createDOMElem(opts);
}
