import { createDOMElem } from "domelemjs";
export function createImage(config) {
    const children = [];
    const imgAttrs = {
        src: config.src,
        alt: config.alt || "",
        class: "image-element",
    };
    if (config.lazy)
        imgAttrs.loading = "lazy";
    if (config.width)
        imgAttrs.width = config.width;
    if (config.height)
        imgAttrs.height = config.height;
    children.push({ tag: "img", attrs: imgAttrs });
    if (config.caption) {
        children.push({ tag: "figcaption", text: config.caption, attrs: { class: "image-caption" } });
    }
    const rootAttrs = { class: `image-container${config.class ? ` ${config.class}` : ""}` };
    if (config.id)
        rootAttrs.id = config.id;
    return createDOMElem({ tag: "figure", parent: config.parent, attrs: rootAttrs, children });
}
